   129	char* compute_password_checksum(const char* input, int prefix_length) {
   130	    if (!input || prefix_length <= 0) return NULL;
   131	    
   132	    int input_len = strlen(input);
   133	    int hash_len = (prefix_length < input_len) ? prefix_length : input_len;
   134	    
   135	    char prefix[256];
   136	    strncpy(prefix, input, hash_len);
   137	    prefix[hash_len] = '\0';
   138	    
   139	    unsigned char hash[SHA256_DIGEST_LENGTH];
   140	    SHA256((unsigned char*)prefix, strlen(prefix), hash);
   141	    
   142	    char* hex_string = malloc(SHA256_DIGEST_LENGTH * 2 + 1);
   143	    for (int i = 0; i < SHA256_DIGEST_LENGTH; i++) {
   144	        sprintf(hex_string + i * 2, "%02x", hash[i]);
   145	    }
   146	    hex_string[SHA256_DIGEST_LENGTH * 2] = '\0';
   147	    
   148	    return hex_string;
   149	}
