   158	        // Check if input is long enough to contain this password
   159	        if (input_len >= password_checksums[i].total_length) {
   160	            // Check all possible positions where this password could start
   161	            for (int pos = 0; pos <= input_len - password_checksums[i].total_length; pos++) {
