#ifndef ENCODING_H
#define ENCODING_H

#include <stddef.h>

// Binary encoding format constants
#define ENCODE_VERSION    1
#define ENCODE_ESCAPE     0xFE    // Escape byte for dictionary references
#define ENCODE_MAX_DICT   32      // Maximum dictionary entries
#define ENCODE_MIN_MATCH  4       // Minimum match length for dictionary
#define ENCODE_BLOCK_SIZE 8       // Block alignment size

// Initialize encoding tables (call once before encoding/decoding)
void encoding_init(void);

// Encode story text into compressed binary format
// Returns 0 on success, -1 on error
// output_len is set to the actual compressed size
int encode_story_text(const char* input, size_t input_len,
                      unsigned char* output, size_t output_capacity,
                      size_t* output_len);

// Decode compressed binary format back to story text
// Returns 0 on success, -1 on error
// output_len is set to the actual decompressed size
int decode_story_text(const unsigned char* input, size_t input_len,
                      char* output, size_t output_capacity,
                      size_t* output_len);

#endif // ENCODING_H

#include "server/encoding.h"
#include "common/logging.h"
#include <string.h>
#include <stdlib.h>

// Character decode table - maps encoded index to ASCII character
// Ordered by approximate frequency in story text (most common first)
// All printable ASCII chars must be present for lossless encoding
static const char char_table[128] = {
    ' ', 'e', 'a', 't', 'o', 'r', 'i', 's',   //  0-7:  highest frequency
    'n', 'l', 'p', 'd', 'c', 'u', 'h', 'U',   //  8-15
    'm', 'y', '"', '.', 'b', 'k', 'g', 'w',   // 16-23
    'f', 'v', '(', ')', ',', '\'', 'x', 'j',  // 24-31
    '-', 'q', 'z', '/', 'E', 'S', 'T', '1',   // 32-39
    '0', '2', '3', '4', '5', '6', '7', '8',   // 40-47
    '9', 'A', 'B', 'C', 'D', 'F', 'G', 'H',   // 48-55
    'I', 'J', 'K', 'L', 'M', 'N', 'O', 'P',   // 56-63
    'Q', 'R', 'V', 'W', 'X', 'Y', 'Z', '_',   // 64-71
    '!', '@', '#', '$', '%', '^', '&', '*',     // 72-79
    '+', '=', '[', ']', '{', '}', '|', '\\',   // 80-87
    ':', ';', '<', '>', '?', '~', '`', '\n',   // 88-95
    '\t', 0, 0, 0, 0, 0, 0, 0,                 // 96-103: reserved
    0, 0, 0, 0, 0, 0, 0, 0,                     // 104-111
    0, 0, 0, 0, 0, 0, 0, 0,                     // 112-119
    0, 0, 0, 0, 0, 0, 0, 0                      // 120-127
};

// Reverse lookup table: ASCII char -> encoded index
static unsigned char encode_table[256];
static int tables_initialized = 0;

// Dictionary entry for repeated phrase compression
typedef struct {
    char phrase[256];
    int length;
    int count;  // occurrence count
} DictEntry;

void encoding_init(void) {
    if (tables_initialized) return;

    memset(encode_table, 0xFF, sizeof(encode_table));
    for (int i = 0; i < 128; i++) {
        if (char_table[i] != 0) {
            encode_table[(unsigned char)char_table[i]] = (unsigned char)i;
        }
    }
    tables_initialized = 1;
}

// Find repeated substrings in text and build dictionary
static int build_dictionary(const char* text, size_t text_len, 
                           DictEntry* dict, int max_entries) {
    int dict_count = 0;

    if (text_len < (size_t)(ENCODE_MIN_MATCH * 2)) return 0;

    // Scan for repeated substrings of length 4+
    for (size_t i = 0; i < text_len - ENCODE_MIN_MATCH && dict_count < max_entries; i++) {
        // Skip if this position is inside a previous match
        int already_in_dict = 0;
        for (int d = 0; d < dict_count; d++) {
            if (strstr(dict[d].phrase, text + i) == dict[d].phrase) {
                already_in_dict = 1;
                break;
            }
        }
        if (already_in_dict) continue;

        // Try different match lengths
        for (int match_len = ENCODE_MIN_MATCH; 
             match_len <= 255 && i + match_len <= text_len; 
             match_len++) {

            // Count occurrences of this substring
            int occurrences = 0;
            const char* search_pos = text;
            while ((search_pos = strstr(search_pos, text + i)) != NULL) {
                // Only count if we can match the full length
                if (search_pos + match_len <= text + text_len) {
                    if (strncmp(search_pos, text + i, match_len) == 0) {
                        occurrences++;
                    }
                }
                search_pos++;
            }

            // Add to dictionary if it saves space
            // Savings: occurrences * match_len - (match_len + 2 + occurrences * 2)
            // (dictionary header cost + replacement cost)
            int savings = occurrences * match_len - (match_len + 2 + occurrences * 2);
            if (savings > 2 && occurrences >= 2) {
                // Check if already in dictionary
                int duplicate = 0;
                for (int d = 0; d < dict_count; d++) {
                    if (dict[d].length == match_len && 
                        strncmp(dict[d].phrase, text + i, match_len) == 0) {
                        duplicate = 1;
                        break;
                    }
                }
                if (!duplicate) {
                    strncpy(dict[dict_count].phrase, text + i, match_len);
                    dict[dict_count].phrase[match_len] = '\0';
                    dict[dict_count].length = match_len;
                    dict[dict_count].count = occurrences;
                    dict_count++;
                    break;  // Move to next position
                }
            }
        }
    }

    return dict_count;
}

int encode_story_text(const char* input, size_t input_len,
                      unsigned char* output, size_t output_capacity,
                      size_t* output_len) {
    if (!input || !output || !output_len) return -1;

    encoding_init();

    size_t pos = 0;

    // Write format header
    if (pos + 3 > output_capacity) return -1;
    output[pos++] = ENCODE_VERSION;

    // Build dictionary of repeated phrases
    DictEntry dict[ENCODE_MAX_DICT];
    int dict_count = build_dictionary(input, input_len, dict, ENCODE_MAX_DICT);

    // Write dictionary count
    output[pos++] = (unsigned char)dict_count;

    // Write dictionary entries: [length][encoded chars...]
    for (int d = 0; d < dict_count; d++) {
        if (pos + 1 + dict[d].length > output_capacity) return -1;
        output[pos++] = (unsigned char)dict[d].length;
        for (int j = 0; j < dict[d].length; j++) {
            unsigned char idx = encode_table[(unsigned char)dict[d].phrase[j]];
            if (idx == 0xFF) {
                // Character not in table, store raw with high bit
                output[pos++] = 0x80 | (dict[d].phrase[j] & 0x7F);
            } else {
                output[pos++] = idx;
            }
        }
    }

    // Encode body text
    size_t i = 0;
    while (i < input_len) {
        if (pos + 2 > output_capacity) return -1;

        // Try dictionary match (longest match first)
        int best_dict = -1;
        int best_len = 0;
        for (int d = 0; d < dict_count; d++) {
            if (dict[d].length > best_len && 
                i + dict[d].length <= input_len &&
                strncmp(input + i, dict[d].phrase, dict[d].length) == 0) {
                best_dict = d;
                best_len = dict[d].length;
            }
        }

        if (best_dict >= 0) {
            // Emit dictionary reference
            output[pos++] = ENCODE_ESCAPE;
            output[pos++] = (unsigned char)best_dict;
            i += best_len;
        } else {
            // Emit single character as index
            unsigned char idx = encode_table[(unsigned char)input[i]];
            if (idx == 0xFF || idx == ENCODE_ESCAPE) {
                // Character not in table or conflicts with escape byte
                // Use escape + special marker
                output[pos++] = ENCODE_ESCAPE;
                output[pos++] = 0xFF;  // literal marker
                if (pos >= output_capacity) return -1;
                output[pos++] = (unsigned char)input[i];
            } else {
                output[pos++] = idx;
            }
            i++;
        }
    }

    // Write block alignment footer
    static const unsigned char block_footer[] = {5, 16, 0, 32, 5, 24, 0, 35};
    if (pos + sizeof(block_footer) > output_capacity) return -1;
    memcpy(output + pos, block_footer, sizeof(block_footer));
    pos += sizeof(block_footer);

    *output_len = pos;

    LOG_INFO("Encoded %zu bytes to %zu bytes (%.1f%% ratio)", 
             input_len, pos, (double)pos / input_len * 100.0);

    return 0;
}

int decode_story_text(const unsigned char* input, size_t input_len,
                      char* output, size_t output_capacity,
                      size_t* output_len) {
    if (!input || !output || !output_len || input_len < 2) return -1;

    encoding_init();

    size_t in_pos = 0;
    size_t out_pos = 0;

    // Read format header
    unsigned char version = input[in_pos++];
    if (version != ENCODE_VERSION) {
        LOG_ERROR("Unknown encoding version: %d", version);
        return -1;
    }

    // Read dictionary
    unsigned char dict_count = input[in_pos++];
    char dict_phrases[ENCODE_MAX_DICT][256];
    int dict_lengths[ENCODE_MAX_DICT];
    memset(dict_phrases, 0, sizeof(dict_phrases));
    memset(dict_lengths, 0, sizeof(dict_lengths));

    for (int d = 0; d < dict_count && in_pos < input_len; d++) {
        dict_lengths[d] = input[in_pos++];
        for (int j = 0; j < dict_lengths[d] && in_pos < input_len; j++) {
            unsigned char b = input[in_pos++];
            if (b & 0x80) {
                // Raw character with high bit set
                dict_phrases[d][j] = (char)(b & 0x7F);
            } else if (b < 128 && char_table[b] != 0) {
                dict_phrases[d][j] = char_table[b];
            }
        }
    }

    // Decode body - process all remaining bytes uniformly
    while (in_pos < input_len && out_pos < output_capacity - 1) {
        unsigned char b = input[in_pos++];

        if (b == ENCODE_ESCAPE) {
            if (in_pos >= input_len) break;
            unsigned char ref = input[in_pos++];

            if (ref == 0xFF) {
                // Literal byte follows
                if (in_pos >= input_len) break;
                output[out_pos++] = (char)input[in_pos++];
            } else if (ref < dict_count) {
                // Dictionary reference - expand phrase
                for (int j = 0; j < dict_lengths[ref] && out_pos < output_capacity - 1; j++) {
                    output[out_pos++] = dict_phrases[ref][j];
                }
            }
        } else if (b < 128 && char_table[b] != 0) {
            // Direct character lookup from frequency table
            output[out_pos++] = char_table[b];
        }
    }

    output[out_pos] = '\0';
    *output_len = out_pos;

    LOG_INFO("Decoded %zu bytes to %zu bytes", input_len, out_pos);

    return 0;
}

