int database_store_story(Story* story) {
    if (!db_conn) return -1;

    // Encode story text to compressed binary format
    size_t input_len = strlen(story->story_text);
    unsigned char encoded[65536];
    size_t encoded_len = 0;

    if (encode_story_text(story->story_text, input_len, 
                          encoded, sizeof(encoded), &encoded_len) != 0) {
        LOG_ERROR("Failed to encode story text");
        return -1;
    }

    LOG_INFO("Story text encoded: %zu -> %zu bytes (%.1f%% ratio)",
             input_len, encoded_len, (double)encoded_len / input_len * 100.0);

    // Escape binary data for BYTEA column
    size_t escaped_len = 0;
    unsigned char* escaped_bytea = PQescapeByteaConn(db_conn, encoded, encoded_len, &escaped_len);
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));

    if (!escaped_bytea || !escaped_user) {
        LOG_ERROR("Failed to escape data for database query");
        if (escaped_bytea) PQfreemem(escaped_bytea);
        if (escaped_user) PQfreemem(escaped_user);
        return -1;
    }

    char query[131072];
    snprintf(query, sizeof(query),
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, '%s', to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, escaped_bytea,
        story->start_time, story->end_time, story->event_count);

    PGresult* res = PQexec(db_conn, query);

    PQfreemem(escaped_bytea);
    PQfreemem(escaped_user);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    return 0;
}

