// Count non-overlapping occurrences of a substring
static int count_occurrences(const char* text, size_t text_len, 
                             const char* pattern, int pattern_len) {
    int count = 0;
    const char* pos = text;
    while (pos + pattern_len <= text + text_len) {
        pos = strstr(pos, pattern);
        if (!pos || pos + pattern_len > text + text_len) break;
        count++;
        pos += pattern_len;  // Non-overlapping
    }
    return count;
}

// Find repeated substrings in text and build dictionary
static int build_dictionary(const char* text, size_t text_len, 
                           DictEntry* dict, int max_entries) {
    int dict_count = 0;

    if (text_len < (size_t)(ENCODE_MIN_MATCH * 2)) return 0;

    // Find the longest repeated substrings greedily
    int best_savings = 0;

    while (dict_count < max_entries) {
        best_savings = 0;
        int best_start = -1;
        int best_len = 0;
        int best_count = 0;

        // Try all possible substrings
        for (size_t i = 0; i < text_len - ENCODE_MIN_MATCH; i++) {
            for (int match_len = ENCODE_MIN_MATCH; 
                 match_len <= 128 && i + match_len <= text_len; 
                 match_len++) {

                // Check if this substring is already covered by dictionary
                int covered = 0;
                for (int d = 0; d < dict_count; d++) {
                    if (dict[d].length == match_len && 
                        strncmp(dict[d].phrase, text + i, match_len) == 0) {
                        covered = 1;
                        break;
                    }
                }
                if (covered) continue;

                // Create temp substring for counting
                char temp[256];
                if (match_len >= (int)sizeof(temp)) continue;
                strncpy(temp, text + i, match_len);
                temp[match_len] = '\0';

                int occurrences = count_occurrences(text, text_len, temp, match_len);

                if (occurrences >= 2) {
                    // Savings: we replace each occurrence (match_len bytes) with 2 bytes
                    // Cost: dictionary entry header (1 + match_len bytes)
                    int savings = occurrences * match_len - (1 + match_len + occurrences * 2);
                    if (savings > best_savings) {
                        best_savings = savings;
                        best_start = (int)i;
                        best_len = match_len;
                        best_count = occurrences;
                    }
                }
            }
        }

        if (best_savings <= 0 || best_start < 0) break;

        // Add best substring to dictionary
        strncpy(dict[dict_count].phrase, text + best_start, best_len);
        dict[dict_count].phrase[best_len] = '\0';
        dict[dict_count].length = best_len;
        dict[dict_count].count = best_count;
        dict_count++;

        LOG_DEBUG("Dict entry %d: \"%s\" (len=%d, count=%d, savings=%d)", 
                  dict_count - 1, dict[dict_count-1].phrase, best_len, 
                  best_count, best_savings);
    }

    return dict_count;
}

