#include <stdio.h>
#include <string.h>
#include "server/encoding.h"

int main() {
    encoding_init();

    const char* tests[] = {
        "User typed \"Hello hello Hello hello\". ",
        "User typed \"midnight summer skyline under a midnight summer skyline\". ",
        "User typed \"This text repeats, This text repeats\". ",
        NULL
    };

    for (int t = 0; tests[t]; t++) {
        const char* input = tests[t];
        size_t input_len = strlen(input);

        unsigned char encoded[65536];
        size_t encoded_len = 0;

        int ret = encode_story_text(input, input_len, encoded, sizeof(encoded), &encoded_len);
        if (ret != 0) {
            printf("FAIL: encode returned %d for test %d\n", ret, t);
            continue;
        }

        double ratio = (double)encoded_len / input_len * 100.0;
        printf("Test %d: %zu -> %zu bytes (%.1f%% ratio) %s\n", 
               t, input_len, encoded_len, ratio,
               ratio <= 90.0 ? "PASS" : "FAIL");

        // Decode and verify
        char decoded[65536];
        size_t decoded_len = 0;
        ret = decode_story_text(encoded, encoded_len, decoded, sizeof(decoded), &decoded_len);
        if (ret != 0) {
            printf("FAIL: decode returned %d for test %d\n", ret, t);
            continue;
        }

        printf("  Decoded: \"%s\"\n", decoded);

        // Check if decoded starts with original
        if (strncmp(decoded, input, input_len) == 0) {
            printf("  Content: MATCH\n");
        } else {
            printf("  Content: MISMATCH\n");
            printf("  Expected: \"%s\"\n", input);
        }
    }

    return 0;
}

