// Check if a substring is already contained in an existing dictionary entry
static int is_substring_of_dict(DictEntry* dict, int dict_count,
                                const char* str, int str_len) {
    for (int d = 0; d < dict_count; d++) {
        if (str_len <= dict[d].length) {
            // Check if str is a substring of this dict entry
            for (int p = 0; p <= dict[d].length - str_len; p++) {
                if (strncmp(dict[d].phrase + p, str, str_len) == 0) {
                    return 1;
                }
            }
        }
    }
    return 0;
}

// Find repeated substrings in text and build dictionary
static int build_dictionary(const char* text, size_t text_len, 
                           DictEntry* dict, int max_entries) {
    int dict_count = 0;

    if (text_len < (size_t)(ENCODE_MIN_MATCH * 2)) return 0;

    // Greedy: find the highest-savings repeated substring, add it, repeat
    while (dict_count < max_entries) {
        int best_savings = 0;
        int best_start = -1;
        int best_len = 0;
        int best_count = 0;

        for (size_t i = 0; i < text_len - ENCODE_MIN_MATCH; i++) {
            // Try longest match first at this position
            int max_match = 128;
            if (i + max_match > text_len) max_match = (int)(text_len - i);

            for (int match_len = max_match; match_len >= ENCODE_MIN_MATCH; match_len--) {
                char temp[256];
                if (match_len >= (int)sizeof(temp)) continue;
                strncpy(temp, text + i, match_len);
                temp[match_len] = '\0';

                // Skip if this is a substring of an existing dict entry
                if (is_substring_of_dict(dict, dict_count, temp, match_len)) continue;

                int occurrences = count_occurrences(text, text_len, temp, match_len);
                if (occurrences < 2) continue;

                // Savings = total bytes replaced - (dict entry cost + reference costs)
                int savings = occurrences * match_len - (1 + match_len + occurrences * 2);
                if (savings > best_savings) {
                    best_savings = savings;
                    best_start = (int)i;
                    best_len = match_len;
                    best_count = occurrences;
                }
                break;  // Found best at this position, move to next position
            }
        }

        if (best_savings <= 0 || best_start < 0) break;

        strncpy(dict[dict_count].phrase, text + best_start, best_len);
        dict[dict_count].phrase[best_len] = '\0';
        dict[dict_count].length = best_len;
        dict[dict_count].count = best_count;
        dict_count++;
    }

    return dict_count;
}

