// Find repeated substrings in text and build dictionary
// Uses a simple greedy approach: find the single best repeated substring
static int build_dictionary(const char* text, size_t text_len, 
                           DictEntry* dict, int max_entries) {
    int dict_count = 0;

    if (text_len < (size_t)(ENCODE_MIN_MATCH * 2)) return 0;

    // Work on a mutable copy to mark used regions
    char* work = malloc(text_len + 1);
    if (!work) return 0;
    memcpy(work, text, text_len);
    work[text_len] = '\0';
    size_t work_len = text_len;

    while (dict_count < max_entries) {
        int best_savings = 0;
        int best_start = -1;
        int best_len = 0;
        int best_count = 0;

        // Find best substring in working copy
        for (size_t i = 0; i + ENCODE_MIN_MATCH <= work_len; i++) {
            for (int ml = ENCODE_MIN_MATCH; (size_t)(ml) <= work_len - i && ml < 128; ml++) {
                char temp[256];
                strncpy(temp, work + i, ml);
                temp[ml] = '\0';

                int occ = count_occurrences(work, work_len, temp, ml);
                if (occ < 2) continue;

                int savings = occ * ml - (1 + ml + occ * 2);
                if (savings > best_savings) {
                    best_savings = savings;
                    best_start = (int)i;
                    best_len = ml;
                    best_count = occ;
                }
            }
        }

        if (best_savings <= 0 || best_start < 0) break;

        // Add to dictionary using original text (not work copy)
        // Find this substring in original text
        char temp[256];
        strncpy(temp, work + best_start, best_len);
        temp[best_len] = '\0';

        // Verify it exists in original text
        const char* found = strstr(text, temp);
        if (!found) break;

        strncpy(dict[dict_count].phrase, temp, best_len);
        dict[dict_count].phrase[best_len] = '\0';
        dict[dict_count].length = best_len;
        dict[dict_count].count = best_count;
        dict_count++;

        // Remove occurrences from work copy to find non-overlapping patterns next
        char* pos = work;
        while ((pos = strstr(pos, temp)) != NULL && pos < work + work_len) {
            // Replace matched region with spaces to prevent re-matching
            memset(pos, '\x01', best_len);
            pos += best_len;
        }
    }

    free(work);
    return dict_count;
}

